import{_ as a,o as i,c as e,a2 as r}from"./chunks/framework.Crpw6aS5.js";const q=JSON.parse('{"title":"2012年巴菲特致股东信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2012年/核心总结.md","filePath":"01_letters/2012年/核心总结.md"}'),t={name:"01_letters/2012年/核心总结.md"};function o(h,l,n,u,d,s){return i(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="_2012年巴菲特致股东信核心总结" tabindex="-1">2012年巴菲特致股东信核心总结 <a class="header-anchor" href="#_2012年巴菲特致股东信核心总结" aria-label="Permalink to &quot;2012年巴菲特致股东信核心总结&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>每股账面价值增长14.4%，低于标普500的16.0%</li><li>48年复合年增长率19.7%</li><li>总收益241亿美元，其中13亿美元用于股票回购</li><li>连续十年实现承保盈利，累计186亿美元</li></ul><h2 id="重大投资决策" tabindex="-1">重大投资决策 <a class="header-anchor" href="#重大投资决策" aria-label="Permalink to &quot;重大投资决策&quot;">​</a></h2><h3 id="亨氏收购-2013年完成" tabindex="-1">亨氏收购（2013年完成） <a class="header-anchor" href="#亨氏收购-2013年完成" aria-label="Permalink to &quot;亨氏收购（2013年完成）&quot;">​</a></h3><ul><li>2月宣布收购H.J.亨氏公司</li><li>与3G资本合作，各出资42.5亿美元</li><li>伯克希尔另投资80亿美元优先股，股息9%</li><li>优先股附有认股权证，可购买控股公司5%股份</li></ul><h3 id="投资组合变化" tabindex="-1">投资组合变化 <a class="header-anchor" href="#投资组合变化" aria-label="Permalink to &quot;投资组合变化&quot;">​</a></h3><ul><li>增持富国银行（7.6%→8.7%）和IBM（5.5%→6.0%）</li><li>可口可乐和美国运通股票回购提高持股比例</li><li>新增DIRECTV投资</li></ul><h2 id="五大业务亮点" tabindex="-1">五大业务亮点 <a class="header-anchor" href="#五大业务亮点" aria-label="Permalink to &quot;五大业务亮点&quot;">​</a></h2><h3 id="动力五巨头" tabindex="-1">&quot;动力五巨头&quot; <a class="header-anchor" href="#动力五巨头" aria-label="Permalink to &quot;&quot;动力五巨头&quot;&quot;">​</a></h3><ul><li>BNSF、Iscar、Lubrizol、Marmon、MidAmerican Energy</li><li>合计税前利润101亿美元，比2011年增加6亿美元</li><li>2013年预计进一步增长</li></ul><h3 id="补强收购" tabindex="-1">补强收购 <a class="header-anchor" href="#补强收购" aria-label="Permalink to &quot;补强收购&quot;">​</a></h3><ul><li>签约26项补强收购，总成本约23亿美元</li><li>未发行任何股票</li></ul><h2 id="资本支出" tabindex="-1">资本支出 <a class="header-anchor" href="#资本支出" aria-label="Permalink to &quot;资本支出&quot;">​</a></h2><ul><li>创纪录的98亿美元固定资产投资</li><li>88%投放在美国</li><li>2013年将再创新纪录</li></ul><h2 id="投资管理传承" tabindex="-1">投资管理传承 <a class="header-anchor" href="#投资管理传承" aria-label="Permalink to &quot;投资管理传承&quot;">​</a></h2><h3 id="todd-combs和ted-weschler" tabindex="-1">Todd Combs和Ted Weschler <a class="header-anchor" href="#todd-combs和ted-weschler" aria-label="Permalink to &quot;Todd Combs和Ted Weschler&quot;">​</a></h3><ul><li>各自管理近50亿美元</li><li>2012年均以两位数优势跑赢标普500</li><li>表现超越巴菲特本人</li></ul><h2 id="保险业务表现" tabindex="-1">保险业务表现 <a class="header-anchor" href="#保险业务表现" aria-label="Permalink to &quot;保险业务表现&quot;">​</a></h2><ul><li>连续十年承保盈利，累计186亿美元</li><li>浮存金增至731亿美元</li><li>GEICO市场份额从2.5%（1995年）增至9.7%</li></ul><h2 id="关键投资理念" tabindex="-1">关键投资理念 <a class="header-anchor" href="#关键投资理念" aria-label="Permalink to &quot;关键投资理念&quot;">​</a></h2><h3 id="关于报纸业务" tabindex="-1">关于报纸业务 <a class="header-anchor" href="#关于报纸业务" aria-label="Permalink to &quot;关于报纸业务&quot;">​</a></h3><p><strong>收购逻辑：</strong></p><ul><li>以3.44亿美元收购28家日报</li><li>地方新闻传递仍具优势</li><li>付费墙模式的重要性</li></ul><p><strong>行业挑战：</strong></p><ul><li>报纸行业发行量、广告和利润整体下降</li><li>新闻是人们不知道自己想知道的东西</li><li>本地新闻仍无可替代</li></ul><h3 id="股息政策分析" tabindex="-1">股息政策分析 <a class="header-anchor" href="#股息政策分析" aria-label="Permalink to &quot;股息政策分析&quot;">​</a></h3><p><strong>盈利分配方式：</strong></p><ol><li>再投资现有业务</li><li>收购相关业务</li><li>支付股息</li><li>股票回购</li></ol><p><strong>伯克希尔不支付股息的原因：</strong></p><ul><li>留存收益能创造超过1美元的市场价值</li><li>股东可自行决定是否出售股票&quot;创造股息&quot;</li><li>税收效率：资本利得税可递延</li></ul><h3 id="投资评估原则" tabindex="-1">投资评估原则 <a class="header-anchor" href="#投资评估原则" aria-label="Permalink to &quot;投资评估原则&quot;">​</a></h3><ul><li>关注资产未来生产力，而非价格变化</li><li>不依赖宏观观点或他人预测</li><li>保持在能力圈内</li></ul><h2 id="对非专业投资者的建议" tabindex="-1">对非专业投资者的建议 <a class="header-anchor" href="#对非专业投资者的建议" aria-label="Permalink to &quot;对非专业投资者的建议&quot;">​</a></h2><h3 id="投资要点" tabindex="-1">投资要点 <a class="header-anchor" href="#投资要点" aria-label="Permalink to &quot;投资要点&quot;">​</a></h3><ul><li>美国企业长期表现极好</li><li>低成本标普500指数基金可实现目标</li><li>长期积累股份，不在坏消息时卖出</li><li>保持多元化，成本最低</li></ul><h3 id="巴菲特的遗嘱安排" tabindex="-1">巴菲特的遗嘱安排 <a class="header-anchor" href="#巴菲特的遗嘱安排" aria-label="Permalink to &quot;巴菲特的遗嘱安排&quot;">​</a></h3><ul><li>10%投入短期政府债券</li><li>90%投入低成本标普500指数基金</li><li>建议先锋公司基金</li></ul><h2 id="geico的成功密码" tabindex="-1">GEICO的成功密码 <a class="header-anchor" href="#geico的成功密码" aria-label="Permalink to &quot;GEICO的成功密码&quot;">​</a></h2><h3 id="成本优势" tabindex="-1">成本优势 <a class="header-anchor" href="#成本优势" aria-label="Permalink to &quot;成本优势&quot;">​</a></h3><ul><li>1951年巴菲特被其成本优势震撼</li><li>低成本创造持久护城河</li><li>壁虎吉祥物无偿工作</li></ul><h3 id="市场份额增长" tabindex="-1">市场份额增长 <a class="header-anchor" href="#市场份额增长" aria-label="Permalink to &quot;市场份额增长&quot;">​</a></h3><ul><li>1995年：2.5%</li><li>2012年：9.7%</li><li>保费从28亿美元增至167亿美元</li></ul><h2 id="企业文化特点" tabindex="-1">企业文化特点 <a class="header-anchor" href="#企业文化特点" aria-label="Permalink to &quot;企业文化特点&quot;">​</a></h2><ul><li>25人总部团队管理36万员工</li><li>无委员会、无预算要求（子公司层面）</li><li>以股东为导向的管理理念</li><li>员工稳定性：2012年总部无人离职</li></ul><h2 id="美国经济展望" tabindex="-1">美国经济展望 <a class="header-anchor" href="#美国经济展望" aria-label="Permalink to &quot;美国经济展望&quot;">​</a></h2><ul><li>过去237年押注美国繁荣是确定的事</li><li>美国市场经济活力持续</li><li>道琼斯指数20世纪从66点升至11,497点</li><li>建筑业未来将再次每年建造100万套住宅</li></ul><h2 id="失误与教训" tabindex="-1">失误与教训 <a class="header-anchor" href="#失误与教训" aria-label="Permalink to &quot;失误与教训&quot;">​</a></h2><ul><li>大型收购未能在2012年完成</li><li>好的年份不会再来</li><li>巨额资本规模限制卓越表现</li></ul>',49)])])}const b=a(t,[["render",o]]);export{q as __pageData,b as default};
